If(
    !IsBlank(incident_type.Text) &&
    !IsBlank(address.Text) &&
    !IsBlank(additional_info.Text) &&
    !IsBlank(user_dropdown.Selected),

    Patch(Tasks, Defaults(Tasks), {
        IncidentType: incident_type.Text,
        Address: address.Text,
        AdditionalInfo: additional_info.Text,
        AssignedTo: user_dropdown.Selected.Email,
        Status: "Pending"
    });
    Refresh(Tasks);
    Reset(incident_type);
    Reset(address);
    Reset(additional_info);
    Reset(user_dropdown);
    Notify("Task assigned successfully!", NotificationType.Success);
    Navigate('Team_leader_send_notification', ScreenTransition.Fade),

    Notify("Please fill in all required fields.", NotificationType.Error)
)

